import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { booksAPI } from '../services/api';
import Logo from '../components/Logo';
import './Home.css';

export default function Home() {
  const { isLoggedIn, isAdmin } = useAuth();
  const [featuredBooks, setFeaturedBooks] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setLoading(true);
    booksAPI.getAll()
      .then(res => setFeaturedBooks((res.data || []).slice(0, 4)))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="home-page">
      {/* Hero */}
      <section className="hero">
        <div className="hero-bg">
          <div className="hero-grid" />
          <div className="hero-glow" />
        </div>
        <div className="container hero-content fade-up">
          <div className="hero-eyebrow">
            <span className="badge badge-gold">BookNest Platform</span>
          </div>
          <h1 className="hero-title">
            Discover Stories<br />
            <em>That Move You</em>
          </h1>
          <p className="hero-subtitle">
            A curated bookstore platform for readers and administrators.
            Browse our catalog, manage books, and explore a world of knowledge.
          </p>
          <div className="hero-actions">
            <Link to="/books" className="btn btn-gold hero-btn">
              Browse Catalog →
            </Link>
            {!isLoggedIn() && (
              <Link to="/register" className="btn btn-outline hero-btn">
                Create Account
              </Link>
            )}
            {isLoggedIn() && (
              <Link to="/dashboard" className="btn btn-outline hero-btn">
                {isAdmin() ? 'Admin Panel' : 'My Dashboard'}
              </Link>
            )}
          </div>
        </div>
      </section>

      {/* Featured Books Section */}
      <section className="featured-books container fade-up">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 'var(--gap-xl)' }}>
          <div>
            <h2 style={{ fontSize: 'var(--font-xl)' }}>Featured Books</h2>
            <p className="text-dim">Discover our latest additions</p>
          </div>
          <Link to="/books" className="btn btn-ghost">View All Catalog →</Link>
        </div>

        {loading ? (
          <div style={{ textAlign: 'center', padding: 'var(--gap-2xl)' }}>
            <div className="spinner" style={{ margin: '0 auto' }}></div>
          </div>
        ) : featuredBooks.length > 0 ? (
          <div className="books-grid" style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', 
            gap: 'var(--gap-xl)' 
          }}>
            {featuredBooks.map((book) => (
              <Link key={book.id} to={`/books/${book.id}`} className="book-card card" style={{ textDecoration: 'none' }}>
                <div className="book-cover" style={{ 
                  height: 280, 
                  background: 'linear-gradient(135deg, var(--bg-soft), #e5e7eb)',
                  borderRadius: 'var(--radius-md)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginBottom: 'var(--gap-md)',
                  fontFamily: 'var(--font-display)',
                  fontSize: 40,
                  fontWeight: 800,
                  color: 'var(--accent-light)'
                }}>
                  {(book.title || 'B')[0].toUpperCase()}
                </div>
                <h3 className="book-title" style={{ fontSize: 16, marginBottom: 4, color: 'var(--text)' }}>{book.title}</h3>
                <p className="book-author text-dim text-sm" style={{ marginBottom: 12 }}>by {book.author}</p>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <span className="text-gold" style={{ fontWeight: 700 }}>₹{book.price?.toFixed(2)}</span>
                  <span className="badge badge-outline" style={{ fontSize: 10 }}>{book.category}</span>
                </div>
              </Link>
            ))}
          </div>
        ) : (
          <div className="empty-state card" style={{ padding: 'var(--gap-2xl)', textAlign: 'center' }}>
            <p className="text-dim">No books available yet.</p>
          </div>
        )}
      </section>

      {/* Features */}
      <section className="features container">
        <div className="features-grid">
          {FEATURES.map((f, i) => (
